#MANUAL SPARQL
PREFIX ns: <http://rdf.freebase.com/ns/>
SELECT DISTINCT  ?x
WHERE {
  ns:m.06x5s ns:sports.sports_championship.events ?x . # Super Bowl
  {
    { ?x ns:sports.sports_championship_event.runner_up ns:m.070xg . } # Seattle Seahawks
    UNION
    { ?x ns:sports.sports_championship_event.champion ns:m.070xg . } # Seattle Seahawks
  }
  ?x ns:time.event.start_date ?d .?x ns:sports.sports_championship_event.champion ns:m.070xg . 
}

#MANUAL SPARQL
PREFIX ns: <http://rdf.freebase.com/ns/>
SELECT DISTINCT ?x
WHERE {
	?x ns:location.country.official_language ns:m.02h40lc . 
}

#MANUAL SPARQL
PREFIX ns: <http://rdf.freebase.com/ns/>
SELECT DISTINCT ?x 
WHERE {
	FILTER (?x != ns:m.0345h)
	{ 
	  ns:m.0345h ns:location.statistical_region.places_exported_to ?y .
	  ?y ns:location.imports_and_exports.exported_to ?x . 
	}
	UNION
	{
	  ns:m.0345h ns:location.statistical_region.places_imported_from ?y .
	  ?y ns:location.imports_and_exports.imported_from ?x . 
	}
}

#MANUAL SPARQL
PREFIX ns: <http://rdf.freebase.com/ns/>
SELECT DISTINCT ?x
WHERE {
  ns:m.02yy8 ns:government.politician.government_positions_held ?y1 .	# Franklin D. Roosevelt
  ?y1 ns:government.government_position_held.office_holder ?y2 ;
      ns:government.government_position_held.office_position_or_title ns:m.060d2 ; # President of the United States
      ns:government.government_position_held.from ?from ;
      ns:government.government_position_held.to ?to .

  FILTER (?from < ?to)
  ?y2 ns:government.politician.government_positions_held ?y3 .	# ?x
  ?y3 ns:government.government_position_held.office_holder ?x .
}

#MANUAL SPARQL
PREFIX ns: <http://rdf.freebase.com/ns/>
SELECT DISTINCT ?x
WHERE {
  ns:m.060d2 ns:government.government_office_or_title.office_holders ?y1 .  # President of the United States
  ?y1 ns:government.government_position_held.office_holder ns:m.0835q .  # William Henry Harrison
  ?y1 ns:government.government_position_held.office_holder ?y2 ;
     ns:government.government_position_held.from ?from ;
     ns:government.government_position_held.to ?to .

  FILTER(xsd:dateTime(?from) - xsd:dateTime(?from) > 0)
  FILTER(xsd:dateTime(?to) - xsd:dateTime(?to) > 0)
  ns:m.060d2 ns:government.government_office_or_title.office_holders ?y3 .  # President of the United States
  ?y3 ns:government.government_position_held.office_holder ?y4 ;
     ns:government.government_position_held.from ?from1 ;
     ns:government.government_position_held.to ?to1 .

  FILTER(xsd:dateTime(?from1) - xsd:dateTime(?from1) > 0)
  FILTER(xsd:dateTime(?to1) - xsd:dateTime(?to1) > 0)
  ?y4 ns:government.government_position_held.office_holder ?y5 ;
     ns:government.government_position_held.from ?from2 ;
     ns:government.government_position_held.to ?to2 .

  FILTER(xsd:dateTime(?from2) - xsd:dateTime

#MANUAL SPARQL
PREFIX ns: <http://rdf.freebase.com/ns/>
SELECT DISTINCT ?dt
WHERE {
  ?e ns:government.governmental_body.members ?y .
  ?y ns:government.government_position_held.from ?from ;
     ns:government.government_position_held.to ?to ;
     ns:government.government_position_held.office_holder ns:m.083q7 . # Woodrow Wilson
  FILTER (?from <= ?to)
}
ORDER BY DESC(xsd:datetime(?from))
LIMIT 1

#MANUAL SPARQL
PREFIX ns: <http://rdf.freebase.com/ns/>
SELECT DISTINCT ?x
WHERE {
	FILTER (?x != ns:m.024v2j)
	{ 
	  # Parents
	  ns:m.024v2j ns:people.person.parents ?x .
	}
	UNION
	{
	  # Children
	  ns:m.024v2j ns:people.person.children ?x .
	}
	UNION
	{
	  # Siblings
	  ns:m.024v2j ns:people.person.sibling_s ?y .
	  ?y ns:people.sibling_relationship.sibling ?x .
	}
	UNION
	{
	  # Spouse
	  ns:m.024v2j ns:people.person.spouse_s ?y .
	  ?y ns:people.marriage.spouse ?x .
	  ?y ns:people.marriage.type_of_union ns:m.04ztj .
	  FILTER (NOT EXISTS {?y ns:people.marriage.to []})
	}?x ns:people.person.children ?c .
?c ns:people.person.gender ns:m.02zsn ( Female) . 
}

#MANUAL SPARQL
PREFIX ns: <http://rdf.freebase.com/ns/>
SELECT DISTINCT ?x
WHERE {
  {
    SELECT ?pFrom 
    WHERE {
      ns:m.02yy8 ns:government.politician.government_positions_held ?y . # Franklin D. Roosevelt
      ?y ns:government.government_position_held.office_position_or_title ?x ; 
         ns:government.government_position_held.basic_title ns:m.060c4 ; # President
         ns:government.government_position_held.from ?pFrom .
    }
  }
  ns:m.02yy8 ns:government.politician.government_positions_held ?y . # Franklin D. Roosevelt
  ?y ns:government.government_position_held.office_position_or_title ?x ; 
     ns:government.government_position_held.from ?from .

  FILTER(xsd:dateTime(?pFrom) - xsd:dateTime(?from) > 0)
}
